#include<cstdio>
#include<vector>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
const int N=2e5+10;int dp[N],n;std::vector<int> G[N];
inline void dfs(const int &u,const int &fa=0)
{
	dp[u]=0;int cnt=0;
	for(int v:G[u])if(v!=fa){dfs(v,u);dp[u]+=dp[v];cnt+=!dp[v];}
	dp[u]+=max(0,cnt-1);
}
int main()
{
	n=read();if(n==1)return puts("0"),0;if(n==2)return puts("1"),0;
	rep(2,n,i){int x=read()+1,y=read()+1;G[x].push_back(y);G[y].push_back(x);}
	rep(1,n,i)if(G[i].size()>2)return dfs(i),printf("%d\n",dp[i]),0;puts("1");
}
